"use client";

import { useState } from "react";
import "./sync.css"; // CSS 파일 별도 생성

export default function AdminSyncPage() {
  const [status, setStatus] = useState("대기 중");
  const [isLoading, setIsLoading] = useState(false);

  // 서울 시청 좌표 예시 (원하는 기준점으로 변경 가능)
  const BASE_X = "126.9780";
  const BASE_Y = "37.5665";

  const handleSync = async () => {
    setIsLoading(true);
    setStatus("데이터 수집 중입니다... (백엔드 작업)");

    try {
      const res = await fetch(`http://localhost:8080/api/night/sync?x=${BASE_X}&y=${BASE_Y}`, {
        method: "POST",
      });
      
      if (res.ok) {
        const msg = await res.text();
        setStatus(`✅ 완료: ${msg}`);
      } else {
        setStatus("❌ 실패: 서버 오류 발생");
      }
    } catch (error) {
      setStatus("❌ 실패: 네트워크 오류");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="sync-container">
      <h1 className="sync-title">약국 데이터 동기화 (Admin)</h1>
      <p className="sync-desc">
        카카오 API를 호출하여 DB에 최신 약국 정보를 저장합니다.<br/>
        (기준 좌표: 서울 시청, 반경 2km)
      </p>

      <div className="status-box">
        <span className="label">상태:</span>
        <span className={`value ${isLoading ? "blink" : ""}`}>{status}</span>
      </div>

      <button 
        onClick={handleSync} 
        disabled={isLoading}
        className="sync-btn"
      >
        {isLoading ? "수집 중..." : "데이터 동기화 시작"}
      </button>
    </div>
  );
}